class PhoneSessionManager {
  sessions = new Map;
  cleanupTimer;
  constructor() {
    this.cleanupTimer = setInterval(() => this.cleanup(), 10 * 60 * 1000);
  }
  create(conversationId, callerId) {
    const session = {
      conversationId,
      callerId,
      startedAt: new Date,
      messages: [],
      metadata: {}
    };
    this.sessions.set(conversationId, session);
    return session;
  }
  get(conversationId) {
    return this.sessions.get(conversationId);
  }
  getOrCreate(conversationId, callerId) {
    return this.sessions.get(conversationId) || this.create(conversationId, callerId);
  }
  addMessage(conversationId, role, content) {
    const session = this.sessions.get(conversationId);
    if (session) {
      session.messages.push({ role, content });
    }
  }
  destroy(conversationId) {
    this.sessions.delete(conversationId);
  }
  cleanup() {
    const cutoff = Date.now() - 60 * 60 * 1000;
    for (const [id, session] of this.sessions) {
      if (session.startedAt.getTime() < cutoff) {
        this.sessions.delete(id);
      }
    }
  }
  stop() {
    clearInterval(this.cleanupTimer);
  }
}

