// src/memory/intents.ts
async function processMemoryIntents(supabase, response, userId) {
  if (!supabase)
    return response;
  let clean = response;
  for (const match of response.matchAll(/\[REMEMBER:\s*(.+?)\]/gi)) {
    await supabase.from("memory").insert({
      type: "fact",
      content: match[1],
      ...userId && { user_id: userId }
    });
    clean = clean.replace(match[0], "");
  }
  for (const match of response.matchAll(/\[GOAL:\s*(.+?)(?:\s*\|\s*DEADLINE:\s*(.+?))?\]/gi)) {
    await supabase.from("memory").insert({
      type: "goal",
      content: match[1],
      deadline: match[2] || null,
      ...userId && { user_id: userId }
    });
    clean = clean.replace(match[0], "");
  }
  for (const match of response.matchAll(/\[DONE:\s*(.+?)\]/gi)) {
    const query = supabase.from("memory").select("id").eq("type", "goal").ilike("content", `%${match[1]}%`).limit(1);
    const { data } = userId ? await query.eq("user_id", userId) : await query;
    if (data?.[0]) {
      await supabase.from("memory").update({
        type: "completed_goal",
        completed_at: new Date().toISOString()
      }).eq("id", data[0].id);
    }
    clean = clean.replace(match[0], "");
  }
  return clean.trim();
}

