// src/channels/telegram/format.ts
function escapeHtml(text) {
  return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}
function toTelegramHtml(markdown) {
  let html = escapeHtml(markdown);
  html = html.replace(/```(?:\w*)\n([\s\S]*?)```/g, "<pre><code>$1</code></pre>");
  html = html.replace(/`([^`]+)`/g, "<code>$1</code>");
  html = html.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
  html = html.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");
  html = html.replace(/~~(.+?)~~/g, "<s>$1</s>");
  html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  return html;
}

// src/channels/telegram/send.ts
var MAX_LENGTH = 4000;
function splitText(text, maxLength = MAX_LENGTH) {
  if (text.length <= maxLength)
    return [text];
  const chunks = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= maxLength) {
      chunks.push(remaining);
      break;
    }
    let splitIndex = remaining.lastIndexOf(`

`, maxLength);
    if (splitIndex === -1)
      splitIndex = remaining.lastIndexOf(`
`, maxLength);
    if (splitIndex === -1)
      splitIndex = remaining.lastIndexOf(" ", maxLength);
    if (splitIndex === -1)
      splitIndex = maxLength;
    chunks.push(remaining.substring(0, splitIndex));
    remaining = remaining.substring(splitIndex).trim();
  }
  return chunks;
}
async function sendResponse(ctx, response, opts) {
  const htmlText = toTelegramHtml(response);
  const chunks = splitText(htmlText);
  for (let i = 0;i < chunks.length; i++) {
    const isFirst = i === 0;
    try {
      await ctx.reply(chunks[i], {
        parse_mode: "HTML",
        ...isFirst && opts?.reply_markup ? { reply_markup: opts.reply_markup } : {}
      });
    } catch (err) {
      const isParseError = err instanceof Error && /bad request|parse|can't parse/i.test(err.message);
      if (isParseError) {
        const plainChunks = splitText(response);
        for (const chunk of plainChunks) {
          await ctx.reply(chunk);
        }
        return;
      }
      throw err;
    }
  }
}
async function sendLongMessage(bot, chatId, text, opts) {
  const htmlText = toTelegramHtml(text);
  const chunks = splitText(htmlText);
  for (let i = 0;i < chunks.length; i++) {
    const isFirst = i === 0;
    try {
      await bot.api.sendMessage(chatId, chunks[i], {
        parse_mode: "HTML",
        ...isFirst && opts?.reply_markup ? { reply_markup: opts.reply_markup } : {}
      });
    } catch (err) {
      const isParseError = err instanceof Error && /bad request|parse|can't parse/i.test(err.message);
      if (isParseError) {
        const plainChunks = splitText(text);
        for (const chunk of plainChunks) {
          await bot.api.sendMessage(chatId, chunk);
        }
        return;
      }
      throw err;
    }
  }
}

// src/channels/telegram/typing.ts
var TYPING_INTERVAL_MS = 4000;
var MAX_TYPING_MS = 120000;
function startTyping(ctx) {
  let stopped = false;
  const sendTyping = () => {
    if (stopped)
      return;
    ctx.replyWithChatAction("typing").catch(() => {});
  };
  sendTyping();
  const interval = setInterval(sendTyping, TYPING_INTERVAL_MS);
  const timeout = setTimeout(() => {
    stopped = true;
    clearInterval(interval);
  }, MAX_TYPING_MS);
  return () => {
    stopped = true;
    clearInterval(interval);
    clearTimeout(timeout);
  };
}

