// src/scheduler/data.ts
var WEATHER_CODES = {
  0: "Clear sky",
  1: "Mainly clear",
  2: "Partly cloudy",
  3: "Overcast",
  45: "Foggy",
  48: "Rime fog",
  51: "Light drizzle",
  53: "Moderate drizzle",
  55: "Dense drizzle",
  56: "Freezing drizzle",
  57: "Heavy freezing drizzle",
  61: "Slight rain",
  63: "Moderate rain",
  65: "Heavy rain",
  66: "Freezing rain",
  67: "Heavy freezing rain",
  71: "Slight snow",
  73: "Moderate snow",
  75: "Heavy snow",
  77: "Snow grains",
  80: "Slight showers",
  81: "Moderate showers",
  82: "Violent showers",
  85: "Slight snow showers",
  86: "Heavy snow showers",
  95: "Thunderstorm",
  96: "Thunderstorm with hail",
  99: "Thunderstorm with heavy hail"
};
async function fetchWeather(latitude, longitude, timezone) {
  try {
    const url = new URL("https://api.open-meteo.com/v1/forecast");
    url.searchParams.set("latitude", latitude.toString());
    url.searchParams.set("longitude", longitude.toString());
    url.searchParams.set("current", "temperature_2m,apparent_temperature,weather_code,relative_humidity_2m,wind_speed_10m");
    url.searchParams.set("daily", "temperature_2m_max,temperature_2m_min,precipitation_probability_max");
    url.searchParams.set("temperature_unit", "fahrenheit");
    url.searchParams.set("wind_speed_unit", "mph");
    url.searchParams.set("timezone", timezone);
    url.searchParams.set("forecast_days", "1");
    const response = await fetch(url.toString());
    if (!response.ok)
      return null;
    const data = await response.json();
    const current = data.current;
    const daily = data.daily;
    return {
      temperature: Math.round(current.temperature_2m),
      apparentTemperature: Math.round(current.apparent_temperature),
      weatherCode: current.weather_code,
      weatherDescription: WEATHER_CODES[current.weather_code] || "Unknown",
      high: Math.round(daily.temperature_2m_max[0]),
      low: Math.round(daily.temperature_2m_min[0]),
      precipitationProbability: daily.precipitation_probability_max[0] || 0,
      humidity: current.relative_humidity_2m,
      windSpeed: Math.round(current.wind_speed_10m)
    };
  } catch (error2) {
    console.error("Weather fetch failed:", error2);
    return null;
  }
}
async function fetchNews(tavilyApiKey, topic = "AI and technology") {
  try {
    const response = await fetch("https://api.tavily.com/search", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        api_key: tavilyApiKey,
        query: `${topic} news today`,
        max_results: 5,
        search_depth: "basic",
        include_answer: false
      })
    });
    if (!response.ok)
      return [];
    const data = await response.json();
    return (data.results || []).map((r) => ({
      title: r.title || "Untitled",
      url: r.url || "",
      snippet: r.content?.substring(0, 200) || ""
    }));
  } catch (error2) {
    console.error("News fetch failed:", error2);
    return [];
  }
}
async function fetchGoals(client3) {
  try {
    const { data } = await client3.rpc("get_active_goals");
    return (data || []).map((g) => ({
      content: g.content,
      deadline: g.deadline ? new Date(g.deadline).toLocaleDateString() : undefined
    }));
  } catch (error2) {
    console.error("Goals fetch failed:", error2);
    return [];
  }
}
async function fetchGoalsRaw(client3) {
  try {
    const { data } = await client3.rpc("get_active_goals");
    return (data || []).map((g) => ({
      id: g.id?.toString() || g.content,
      content: g.content,
      deadlineRaw: g.deadline || undefined
    }));
  } catch {
    return [];
  }
}
async function fetchFacts(client3) {
  try {
    const { data } = await client3.rpc("get_facts");
    return (data || []).map((f) => f.content);
  } catch (error2) {
    console.error("Facts fetch failed:", error2);
    return [];
  }
}
async function fetchActivitySummary(client3, timezone) {
  try {
    const { data: recentMessages } = await client3.rpc("get_recent_messages", {
      limit_count: 20
    });
    const now = new Date;
    let lastMessageTime = null;
    let hoursSinceLastMessage = Infinity;
    let messageCountToday = 0;
    const topics = [];
    if (recentMessages?.length) {
      lastMessageTime = recentMessages[0].created_at;
      hoursSinceLastMessage = (now.getTime() - new Date(lastMessageTime).getTime()) / (1000 * 60 * 60);
      const todayStr = now.toLocaleDateString("en-US", { timeZone: timezone });
      for (const msg of recentMessages) {
        const msgDate = new Date(msg.created_at).toLocaleDateString("en-US", {
          timeZone: timezone
        });
        if (msgDate === todayStr)
          messageCountToday++;
        if (msg.role === "user" && topics.length < 3) {
          topics.push(msg.content.substring(0, 80));
        }
      }
    }
    return {
      lastMessageTime,
      hoursSinceLastMessage,
      messageCountToday,
      recentTopics: topics
    };
  } catch (error2) {
    console.error("Activity fetch failed:", error2);
    return {
      lastMessageTime: null,
      hoursSinceLastMessage: Infinity,
      messageCountToday: 0,
      recentTopics: []
    };
  }
}
async function fetchTaskSummary(client3) {
  try {
    const todayStart = new Date;
    todayStart.setHours(0, 0, 0, 0);
    const [activeResult, completedResult] = await Promise.all([
      client3.from("tasks").select("description, status").in("status", ["pending", "running"]),
      client3.from("tasks").select("description").eq("status", "completed").gte("updated_at", todayStart.toISOString())
    ]);
    return {
      activeTasks: (activeResult.data || []).map((t) => ({
        description: t.description,
        status: t.status
      })),
      completedToday: (completedResult.data || []).map((t) => ({
        description: t.description
      }))
    };
  } catch (error2) {
    console.error("Tasks fetch failed:", error2);
    return { activeTasks: [], completedToday: [] };
  }
}

// src/tools/builtin/weather.ts
function createWeatherTool(location, user) {
  return {
    definition: {
      name: "get_weather",
      description: "Get current weather conditions and forecast for the user's location. " + "Returns temperature, conditions, high/low, precipitation, humidity, and wind.",
      input_schema: {
        type: "object",
        properties: {},
        required: []
      }
    },
    async execute() {
      const data = await fetchWeather(location.latitude, location.longitude, user.timezone);
      if (!data)
        return "Weather data unavailable.";
      const city = location.cityName ? ` (${location.cityName})` : "";
      return [
        `Weather${city}:`,
        `Current: ${data.temperature}\xB0F (feels like ${data.apparentTemperature}\xB0F)`,
        `Conditions: ${data.weatherDescription}`,
        `High: ${data.high}\xB0F / Low: ${data.low}\xB0F`,
        `Precipitation: ${data.precipitationProbability}%`,
        `Humidity: ${data.humidity}%`,
        `Wind: ${data.windSpeed} mph`
      ].join(`
`);
    },
    scope: "both",
    approval: "never",
    category: "information"
  };
}

// src/tools/builtin/search.ts
function createSearchTool(tavilyApiKey) {
  return {
    definition: {
      name: "web_search",
      description: "Search the web for current information. Returns relevant results with titles, URLs, and content snippets. " + "Use this for questions that need up-to-date data, news, or facts you don't know.",
      input_schema: {
        type: "object",
        properties: {
          query: {
            type: "string",
            description: "The search query"
          },
          max_results: {
            type: "number",
            description: "Max results to return (default 5, max 10)"
          }
        },
        required: ["query"]
      }
    },
    async execute(input) {
      const query = input.query;
      const maxResults = Math.min(input.max_results || 5, 10);
      const response = await fetch("https://api.tavily.com/search", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          api_key: tavilyApiKey,
          query,
          max_results: maxResults,
          include_answer: true
        })
      });
      if (!response.ok) {
        throw new Error(`Search failed: ${response.status} ${response.statusText}`);
      }
      const data = await response.json();
      let result = "";
      if (data.answer)
        result += `Summary: ${data.answer}

`;
      for (const r of data.results || []) {
        result += `Title: ${r.title}
URL: ${r.url}
Content: ${r.content}

`;
      }
      return result || "No results found.";
    },
    scope: "both",
    approval: "never",
    category: "search"
  };
}

// src/tools/builtin/memory-search.ts
function createMemorySearchTool(memory) {
  return {
    definition: {
      name: "search_memory",
      description: "Search the user's long-term memory using semantic similarity. " + "Use this when the user references something from a PREVIOUS session or from days/weeks ago, " + "asks about stored facts, goals, or preferences, or when the recent conversation context " + "doesn't contain the information needed. " + "Do NOT use this for information visible in the current conversation context above.",
      input_schema: {
        type: "object",
        properties: {
          query: {
            type: "string",
            description: "Natural language search query"
          },
          type: {
            type: "string",
            enum: ["all", "facts", "goals", "messages"],
            description: "Filter by memory type (default: all)"
          }
        },
        required: ["query"]
      }
    },
    async execute(input) {
      const query = input.query;
      const type = input.type || "all";
      const parts = [];
      if (type === "all" || type === "messages") {
        const relevant = await memory.getRelevantContext(query);
        if (relevant)
          parts.push(relevant);
      }
      if (type === "all" || type === "facts" || type === "goals") {
        const memCtx = await memory.getMemoryContext();
        if (memCtx)
          parts.push(memCtx);
      }
      return parts.join(`

`) || "No relevant memories found.";
    },
    scope: "chat",
    approval: "never",
    category: "memory"
  };
}

// src/tools/builtin/datetime.ts
function createDateTimeTool(defaultTimezone) {
  return {
    definition: {
      name: "get_datetime",
      description: "Get the current date, time, day of week, and related information. " + "Can convert between timezones. Use this for time-sensitive questions.",
      input_schema: {
        type: "object",
        properties: {
          timezone: {
            type: "string",
            description: `IANA timezone (default: ${defaultTimezone})`
          },
          format: {
            type: "string",
            enum: ["full", "date", "time", "iso"],
            description: "Output format (default: full)"
          }
        },
        required: []
      }
    },
    async execute(input) {
      const tz = input.timezone || defaultTimezone;
      const format = input.format || "full";
      const now = new Date;
      if (format === "iso")
        return now.toISOString();
      if (format === "date") {
        return now.toLocaleDateString("en-US", {
          timeZone: tz,
          weekday: "long",
          year: "numeric",
          month: "long",
          day: "numeric"
        });
      }
      if (format === "time") {
        return now.toLocaleTimeString("en-US", {
          timeZone: tz,
          hour: "2-digit",
          minute: "2-digit",
          second: "2-digit"
        });
      }
      return now.toLocaleString("en-US", {
        timeZone: tz,
        weekday: "long",
        year: "numeric",
        month: "long",
        day: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        timeZoneName: "short"
      });
    },
    scope: "both",
    approval: "never",
    category: "information"
  };
}

// src/tools/builtin/fetch-url.ts
function createFetchUrlTool2() {
  return {
    definition: {
      name: "fetch_url",
      description: "Fetch the content of a web page and convert it to readable text. " + "Use this to read articles, documentation, blog posts, or any web page in detail.",
      input_schema: {
        type: "object",
        properties: {
          url: {
            type: "string",
            description: "The URL to fetch"
          }
        },
        required: ["url"]
      }
    },
    async execute(input) {
      const url = input.url;
      const response = await fetch(url, {
        headers: {
          "User-Agent": "Bright-AI-Assistant/1.0",
          Accept: "text/html,application/xhtml+xml,text/plain"
        },
        signal: AbortSignal.timeout(15000)
      });
      if (!response.ok) {
        throw new Error(`Fetch failed: ${response.status} ${response.statusText}`);
      }
      const html = await response.text();
      const text = html.replace(/<script[\s\S]*?<\/script>/gi, "").replace(/<style[\s\S]*?<\/style>/gi, "").replace(/<[^>]+>/g, " ").replace(/&nbsp;/g, " ").replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\s+/g, " ").trim();
      const maxLen = 12000;
      if (text.length > maxLen) {
        return text.substring(0, maxLen) + `

[Truncated \u2014 page was too long]`;
      }
      return text;
    },
    scope: "both",
    approval: "never",
    category: "search"
  };
}

// src/tools/builtin/conversation-search.ts
function createConversationSearchTool(memory) {
  return {
    definition: {
      name: "search_conversations",
      description: "Search past conversation messages by keyword and time range. " + "Use this when the user asks about something specific they said or discussed " + "that isn't in the recent conversation context \u2014 e.g., 'what did I say about X last week?', " + "'find that recipe I asked about'. More precise than semantic search for keyword lookups.",
      input_schema: {
        type: "object",
        properties: {
          query: {
            type: "string",
            description: "Keyword or phrase to search for in past messages"
          },
          hours: {
            type: "number",
            description: "How far back to search in hours (default: 72, max: 720)"
          }
        },
        required: ["query"]
      }
    },
    async execute(input) {
      const query = input.query;
      const hours = Math.min(input.hours || 72, 720);
      return memory.getConversationHistory({ query, hours });
    },
    scope: "chat",
    approval: "never",
    category: "memory"
  };
}

// src/tools/index.ts
function createBuiltinTools(config, memory) {
  const tools = [];
  tools.push(createDateTimeTool(config.user.timezone));
  tools.push(createFetchUrlTool2());
  tools.push(createMemorySearchTool(memory));
  tools.push(createConversationSearchTool(memory));
  if (config.location) {
    tools.push(createWeatherTool(config.location, config.user));
  }
  if (config.tasks.tavilyApiKey) {
    tools.push(createSearchTool(config.tasks.tavilyApiKey));
  }
  return tools;
}

